/* 
 * Macro is intended to be used in the customization functions for dispatching events to the state machine.
 * This macro should be used instead of the TankDrainEvent() function due to the Key Statements
 *     state variable =
 * and
 *     developer variables =
 * These Key Statements directly affect the function arguments of the customization functions and using the macro
 * DISPATCH_FSM_EVENT(event) will abstract the function arguments, allowing the developer to not have to modify code when the
 * Key Statements are removed/added to the PlantUML text.
 *
 * @param event = TANKDRAIN_FSM_EVENT_TYPE
 */
#define DISPATCH_FSM_EVENT(event)\
    TankDrainFsmEvent(event, fsm_var)

/*
 * Macro is used to define the function arguments to the state machine customization functions.
 * The arguments are defined as a macro to abstract the state machine variables and developer variables
 * from the customization functions headers added to the module.c file.  This was done to prevent duplicate
 * customization functions from being defined in the module.c file when the developer adds or modifies the
 * Key Statements state variable = OR developer variables =.
 */
#define FSM_CUSTOMIZATION_FUNCTION_ARGUMENT\
    TANKDRAIN_FSM_VAR_TYPE * fsm_var /* DO NOT USE, used by the auto-generated code for controlling execution of the state machine */

/*
 * Macro is used to define the function arguments to the state machine guard functions.
 * The arguments are defined as a macro to abstract the developer variables. This was
 * done to prevent duplicate guard functions from being defined in the module.c file
 * when the developer adds or modifies the Key Statement
 *     developer variables =.
 */
#define FSM_GUARD_FUNCTION_ARGUMENT\
    void

// TankDrain state machine states
typedef enum
{
    FSM_STATE_NONE,
    FSM_STATE_TANK_DRAIN, // PlantUML diagram state TANK_DRAIN
    FSM_STATE_FILL_CHECK_SUBCYCLE, // PlantUML diagram state FILL_CHECK_SUBCYCLE
    FSM_STATE_TANK_DRAIN_COMPLETE, // PlantUML diagram state TANK_DRAIN_COMPLETE
    NUM_OF_STATES
} TANKDRAIN_FSM_STATE_TYPE;

// declaration of the structure that will be passed as a function argument to the state machine auto generated functions
typedef struct
{
    TANKDRAIN_FSM_STATE_TYPE State; // the current state of the state machine
    BOOL_TYPE Transition; // TRUE event triggered a state transition else FALSE
} TANKDRAIN_FSM_VAR_TYPE;

// Tank Drain State Machine state machine events
typedef enum
{
    // private events
    FSM_EVENT_TANKDRAINCOMPLETED = 1, // PlantUML diagram event TankDrainCompleted
    FSM_EVENT_WATERCHECK // PlantUML diagram event WaterCheck
} TANKDRAIN_FSM_EVENT_TYPE;

// Tank Drain State Machine state machine control functions
static void TankDrainFsmInitialize(TANKDRAIN_FSM_STATE_TYPE * state);
static void TankDrainFsmExecute(TANKDRAIN_FSM_STATE_TYPE * state);
static void TankDrainFsmEvent(TANKDRAIN_FSM_EVENT_TYPE event, TANKDRAIN_FSM_VAR_TYPE * fsm_var);
static TANKDRAIN_FSM_VAR_TYPE TankDrainBuildFsmVar(TANKDRAIN_FSM_STATE_TYPE state);

// Tank Drain State Machine state machine customization function prototypes
static void ResetSubcycleExecution(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void TankDrain(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void TankDrainInitialCheck(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void WaitSubcycleExecution(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);

//===================================================================================================================
// Tank Drain State Machine definitions.
//===================================================================================================================
/**
 * @brief Configures the TankDrain state machine to start execution from the Pseudo Initial state.
 * @param state: pointer to the state machine state variable
 */
static void TankDrainFsmInitialize(TANKDRAIN_FSM_STATE_TYPE * state)
{
    // define the initial state
    TANKDRAIN_FSM_VAR_TYPE fsm_var = TankDrainBuildFsmVar(FSM_STATE_TANK_DRAIN);
    // state entry actions
    TankDrainInitialCheck(&fsm_var);
    *state = fsm_var.State;
}

/**
 * @brief Executes the TankDrain state machine do actions.
 * @param state: pointer to the state machine state variable
 */
static void TankDrainFsmExecute(TANKDRAIN_FSM_STATE_TYPE * state)
{
    TANKDRAIN_FSM_VAR_TYPE fsm_var = TankDrainBuildFsmVar(*state);
    switch ( fsm_var.State )
    {
        default:
            // do nothing
            break;
        case FSM_STATE_TANK_DRAIN: // PlantUML diagram state TANK_DRAIN
            TankDrain(&fsm_var);
            break;
        case FSM_STATE_FILL_CHECK_SUBCYCLE: // PlantUML diagram state FILL_CHECK_SUBCYCLE
            WaitSubcycleExecution(&fsm_var);
            break;
    }
    *state = fsm_var.State;
}

/**
 * NOTE: The DISPATCH_FSM_EVENT(event) macro should be used instead of this function to dispatch events to the
 *       state machine to make maintaining and updating the state machine customization functions.
 *
 * @brief Dispatch the event to the TankDrain state machine and consume it.
 * @param event: the event to dispatch to the state machine
 * @param state: pointer to the finite state machine variables
 */
static void TankDrainFsmEvent(TANKDRAIN_FSM_EVENT_TYPE event, TANKDRAIN_FSM_VAR_TYPE * fsm_var)
{
    fsm_var->Transition = FALSE;
    switch ( event )
    {
        default:
            // do nothing
            break;
        case FSM_EVENT_TANKDRAINCOMPLETED: // event TankDrainCompleted
            switch ( fsm_var->State ) // state from
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_TANK_DRAIN: // state TANK_DRAIN
                    {
                        // go to state TANK_DRAIN_COMPLETE
                        fsm_var->State = FSM_STATE_TANK_DRAIN_COMPLETE;
                        fsm_var->Transition = TRUE;
                    }
                    break;
                case FSM_STATE_FILL_CHECK_SUBCYCLE: // state FILL_CHECK_SUBCYCLE
                    {
                        // go to state TANK_DRAIN_COMPLETE
                        fsm_var->State = FSM_STATE_TANK_DRAIN_COMPLETE;
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_WATERCHECK: // event WaterCheck
            switch ( fsm_var->State ) // state from
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_TANK_DRAIN: // state TANK_DRAIN
                    {
                        // go to state FILL_CHECK_SUBCYCLE
                        fsm_var->State = FSM_STATE_FILL_CHECK_SUBCYCLE;
                        // state entry actions
                        ResetSubcycleExecution(fsm_var);
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
    }
}

/**
 * @brief Define the TANKDRAIN_FSM_VAR_TYPE with the passed state argument
 * @param state = the current state of the state machine
 * @return = the TANKDRAIN_FSM_VAR_TYPE initialized with the state argument
 */
static TANKDRAIN_FSM_VAR_TYPE TankDrainBuildFsmVar(TANKDRAIN_FSM_STATE_TYPE state)
{
    TANKDRAIN_FSM_VAR_TYPE fsm_var;
    fsm_var.State = state;
    fsm_var.Transition = FALSE;
    return ( fsm_var );
}



#endif /* TANKDRAIN_FSM_H_ */
